// Entrada: items del nodo SQL (GetThread) -> cada item es un mensaje
const items = $input.all().map(i => i.json);

// 1) Definiciones de columnas (ajusta nombres si cambian)
const schema = {
  "MensajeId": "ID interno del mensaje en tu base (PK).",
  "MensajeThreadChatId": "ID del hilo (thread) interno para agrupar conversación.",
  "Mensaje_role": "Rol del mensaje: 'user' o 'assistant'.",
  "MensajeFechaCreacion": "Fecha/hora ISO de creación del mensaje.",
  "Mensaje_Text": "Texto del mensaje (contenido).",
};

// 2) Ordenar por fecha ASC (más antiguo -> más nuevo)
const sorted = items
  .filter(m => m.MensajeFechaCreacion) // por seguridad
  .sort((a, b) => new Date(a.MensajeFechaCreacion) - new Date(b.MensajeFechaCreacion));

// 3) Último mensaje (más reciente)
const last = sorted.length ? sorted[sorted.length - 1] : null;

// 4) Historial compacto para el prompt (texto)
const historyText = sorted.map(m => {
  const role = (m.Mensaje_role || "unknown").toUpperCase();
  const dt = m.MensajeFechaCreacion || "";
  const text = (m.Mensaje_Text || "").trim();
  return `${role} | ${dt} | ${text}`;
}).join("\n");

// 5) También te dejo “último mensaje” como string directo
const lastText = last
  ? `${(last.Mensaje_role || "unknown").toUpperCase()} | ${last.MensajeFechaCreacion} | ${(last.Mensaje_Text || "").trim()}`
  : "";

// Output final
return [{
  json: {
    schema_explicado: schema,
    total_mensajes: sorted.length,
    mensajes_ordenados: sorted,
    ultimo_mensaje: last,
    historial_texto: historyText,
    ultimo_mensaje_texto: lastText,
  }
}];

