  0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,
  0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,
  0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,
  0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2
];

function sha256Bytes(bytes) {
  const l = bytes.length;
  const bitLenHi = Math.floor((l * 8) / 0x100000000);
  const bitLenLo = (l * 8) >>> 0;

  // padding: 1 + k + 8 bytes length
  const withOne = l + 1;
  const padLen = (withOne % 64 <= 56) ? (56 - (withOne % 64)) : (56 + (64 - (withOne % 64)));
  const total = withOne + padLen + 8;

  const msg = new Uint8Array(total);
  msg.set(bytes, 0);
  msg[l] = 0x80;

  // append 64-bit big-endian length
  msg[total - 8] = (bitLenHi >>> 24) & 0xff;
  msg[total - 7] = (bitLenHi >>> 16) & 0xff;
  msg[total - 6] = (bitLenHi >>> 8) & 0xff;
  msg[total - 5] = (bitLenHi >>> 0) & 0xff;
  msg[total - 4] = (bitLenLo >>> 24) & 0xff;
  msg[total - 3] = (bitLenLo >>> 16) & 0xff;
  msg[total - 2] = (bitLenLo >>> 8) & 0xff;
  msg[total - 1] = (bitLenLo >>> 0) & 0xff;

  let h0=0x6a09e667, h1=0xbb67ae85, h2=0x3c6ef372, h3=0xa54ff53a;
  let h4=0x510e527f, h5=0x9b05688c, h6=0x1f83d9ab, h7=0x5be0cd19;

  const w = new Uint32Array(64);

  for (let i = 0; i < msg.length; i += 64) {
    for (let t = 0; t < 16; t++) {
      const j = i + t * 4;
      w[t] = ((msg[j] << 24) | (msg[j+1] << 16) | (msg[j+2] << 8) | (msg[j+3])) >>> 0;
    }
    for (let t = 16; t < 64; t++) {
      w[t] = (s1(w[t-2]) + w[t-7] + s0(w[t-15]) + w[t-16]) >>> 0;
    }

    let a=h0,b=h1,c=h2,d=h3,e=h4,f=h5,g=h6,h=h7;

    for (let t = 0; t < 64; t++) {
      const T1 = (h + S1(e) + ch(e,f,g) + K[t] + w[t]) >>> 0;
      const T2 = (S0(a) + maj(a,b,c)) >>> 0;
      h=g; g=f; f=e;
      e=(d + T1) >>> 0;
      d=c; c=b; b=a;
      a=(T1 + T2) >>> 0;
    }

    h0=(h0 + a) >>> 0;
    h1=(h1 + b) >>> 0;
    h2=(h2 + c) >>> 0;
    h3=(h3 + d) >>> 0;
    h4=(h4 + e) >>> 0;
    h5=(h5 + f) >>> 0;
    h6=(h6 + g) >>> 0;
    h7=(h7 + h) >>> 0;
  }

  const out = new Uint8Array(32);
  const H = [h0,h1,h2,h3,h4,h5,h6,h7];
  for (let i = 0; i < 8; i++) {
    out[i*4]   = (H[i] >>> 24) & 0xff;
    out[i*4+1] = (H[i] >>> 16) & 0xff;
    out[i*4+2] = (H[i] >>> 8)  & 0xff;
    out[i*4+3] = (H[i] >>> 0)  & 0xff;
  }
  return out;
}

const bytes = new TextEncoder().encode(String(text));
const hashBytes = sha256Bytes(bytes);
const hashHex = Array.from(hashBytes).map(b => b.toString(16).padStart(2,'0')).join('');

return [{ json: { hash: hashHex } }];

