// 1) Texto crudo del nodo IASintetizador
const raw = $input.first().json.content?.parts?.[0]?.text ?? "";

// Helpers
const stripCodeFences = (s) =>
  String(s)
    .replace(/```(?:json)?\s*/gi, "") // quita ```json o ```
    .replace(/```/g, "")
    .trim();

const extractJsonObjectString = (s) => {
  const t = stripCodeFences(s);
  const start = t.indexOf("{");
  const end = t.lastIndexOf("}");
  if (start === -1 || end === -1 || end <= start) return null;
  return t.slice(start, end + 1).trim();
};

const tryParseJson = (s) => {
  // intento 1: parse directo
  try {
    let parsed = JSON.parse(s);

    // doble stringificado
    if (typeof parsed === "string") {
      parsed = JSON.parse(parsed);
    }
    return parsed;
  } catch (e1) {
    // intento 2: recortar entre llaves y limpiar trailing commas típicas
    try {
      let candidate = extractJsonObjectString(s);
      if (!candidate) return null;

      // quitar comas colgantes antes de } o ]
      candidate = candidate.replace(/,\s*([}\]])/g, "$1");

      let parsed = JSON.parse(candidate);
      if (typeof parsed === "string") parsed = JSON.parse(parsed);
      return parsed;
    } catch (e2) {
      return null;
    }
  }
};

// 2) Convertir respuesta a mensaje final (preferir parsed.texto)
let msg = raw;
const parsed = tryParseJson(raw);
if (parsed && typeof parsed === "object" && typeof parsed.texto === "string") {
  msg = parsed.texto;
} else {
  // Si no era JSON, igual limpiamos fences por si venía en markdown
  msg = stripCodeFences(raw);
}

// 3) Convertir escapes escritos como texto (si quedaron literales)
msg = String(msg)
  .replace(/\\n/g, "\n")
  .replace(/\\r/g, "")
  .replace(/\\t/g, " ");

// 4) Limpieza de markdown y normalización
const clean = msg
  .replace(/\*\*/g, "")
  .replace(/\*/g, "")
  .replace(/#{1,6}\s+/g, "")
  .replace(/\n{3,}/g, "\n\n")
  .replace(/[\u201C\u201D]/g, '"') // comillas dobles tipográficas -> "
  .replace(/[\u2018\u2019]/g, "'") // comillas simples tipográficas -> '
  .trim();

// 5) Límite 900 caracteres
const final = clean.length > 900
  ? clean.substring(0, 870) + "...\n¿Más info? contacto@sandiegoapart.com 😊"
  : clean;

// 6) Texto JSON-safe (escapa " y convierte saltos reales a \n)
const final_json = JSON.stringify(final).slice(1, -1);

return [
  {
    json: {
      texto_final: final,
      texto_final_json: final_json,
      largo: final.length,
    },
  },
];

